  `idempresa_id` bigint DEFAULT NULL,
  `familia_id` bigint DEFAULT NULL,
  `margen` decimal(5,2) NOT NULL,
  `precio_compra` decimal(11,2) NOT NULL,
  `margen2` decimal(5,2) NOT NULL,
  `imagen_cloud` varchar(255) DEFAULT NULL,
